INSERT INTO `post` VALUES (1, NULL, 'Giới thiệu', '', 'Là đơn vị cung cấp và thi công các sản phẩm vách ngăn tiện ích cho trường học, bệnh viện, sân bay, nhà vệ sinh, văn phòng.\r\nRa đời từ năm 2016, đến nay đã xây dựng được lòng tin cho khách hàng bởi dịch vụ chuyên nghiệp, chất lượng vật liệu cao cấp.</br>\r\nChúng tôi luôn nỗ lực phấn đấu giúp khách hàng tìm ra giải pháp thi công tối ưu nhất. Sao cho vẫn đảm bảo công năng, chất lượng của công trình những vẫn phải tiết kiệm chi phí nhất.', '<p style=\"text-align:center\"><span style=\"font-size:18px\"><span style=\"color:#000000; font-family:Tahoma,Geneva,sans-serif\"><strong>QU&Aacute; TR&Igrave;NH PH&Aacute;T TRIỂN</strong></span></span></p>\r\n\r\n<p><span style=\"color:#000000\"><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">L&agrave; đơn vị cung cấp v&agrave; thi c&ocirc;ng c&aacute;c sản phẩm v&aacute;ch ngăn tiện &iacute;ch cho trường học, bệnh viện, s&acirc;n bay, nh&agrave; vệ sinh, văn ph&ograve;ng.</span></span></span></p>\r\n\r\n<p><span style=\"color:#000000\"><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">Ra đời từ năm 2016, đến nay đ&atilde; x&acirc;y dựng được l&ograve;ng tin cho kh&aacute;ch h&agrave;ng bởi dịch vụ chuy&ecirc;n nghiệp, chất lượng vật liệu cao cấp.</span></span></span></p>\r\n\r\n<p><span style=\"color:#000000\"><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">Ch&uacute;ng t&ocirc;i lu&ocirc;n nỗ lực phấn đấu gi&uacute;p kh&aacute;ch h&agrave;ng t&igrave;m ra giải ph&aacute;p thi c&ocirc;ng tối ưu nhất. Sao cho vẫn đảm bảo c&ocirc;ng năng, chất lượng của c&ocirc;ng tr&igrave;nh những vẫn phải tiết kiệm chi ph&iacute; nhất.&nbsp;</span></span></span></p>\r\n\r\n<p style=\"margin-left:280px\"><span style=\"color:#000000\"><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">&nbsp;</span></span></span></p>\r\n\r\n<p style=\"text-align:center\"><span style=\"font-size:18px\"><span style=\"color:#000000\"><strong><span style=\"font-family:Tahoma,Geneva,sans-serif\">TẦM NH&Igrave;N V&Agrave; SỨ MỆNH</span></strong></span></span></p>\r\n\r\n<p><span style=\"color:#000000\"><strong><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">TẦM NH&Igrave;N</span></span></strong></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"color:#000000\"><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">&nbsp;L&agrave; đơn vị uy t&iacute;n h&agrave;ng đầu trong c&ocirc;ng cuộc thi c&ocirc;ng c&aacute;c sản phẩm v&aacute;ch ngăn tại Việt Nam</span></span></span></li>\r\n</ul>\r\n\r\n<p><span style=\"color:#000000\"><strong><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">SỨ MỆNH</span></span></strong></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"color:#000000\"><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">Ch&uacute;ng t&ocirc;i cam kết mang đến sự h&agrave;i l&ograve;ng cho kh&aacute;ch h&agrave;ng bằng những sản phẩm chất lượng cao v&agrave; dịch vụ thi c&ocirc;ng chuy&ecirc;n nghiệp nhất. Ch&uacute;ng t&ocirc;i c&oacute; tr&aacute;ch nhiệm trước những cam kết với kh&aacute;ch h&agrave;ng.</span></span></span></li>\r\n</ul>\r\n\r\n<p><span style=\"color:#000000\"><strong><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">GI&Aacute; TRỊ CỐT L&Otilde;I</span></span></strong></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"color:#000000\"><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">Kh&aacute;ch h&agrave;ng l&agrave; trọng t&acirc;m: lu&ocirc;n tận t&acirc;m với kh&aacute;ch h&agrave;ng.</span></span></span></li>\r\n	<li><span style=\"color:#000000\"><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">L&agrave;m việc chuy&ecirc;n nghiệp: lu&ocirc;n phục vụ kh&aacute;ch h&agrave;ng với dịch vụ chuy&ecirc;n nghiệp nhất.</span></span></span></li>\r\n	<li><span style=\"color:#000000\"><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">Đặt chữ t&iacute;n l&ecirc;n h&agrave;ng đầu: tin v&agrave;o mối quan hệ hợp t&aacute;c l&acirc;u d&agrave;i.</span></span></span></li>\r\n</ul>\r\n\r\n<p><span style=\"color:#000000\"><strong><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">V&Igrave; SAO N&Ecirc;N CHỌN &nbsp;?</span></span></strong></span></p>\r\n\r\n<p><span style=\"color:#000000\"><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">l&agrave; c&ocirc;ng ty c&oacute; hơn 5&nbsp;năm kinh nghiệm v&agrave; c&oacute; uy t&iacute;n trong ng&agrave;nh.</span></span></span></p>\r\n\r\n<p><span style=\"color:#000000\"><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">c&oacute; nhiều mẫu m&atilde;, m&agrave;u sắc đa dạng cho kh&aacute;ch h&agrave;ng lựa chọn.</span></span></span></p>\r\n\r\n<p><span style=\"color:#000000\"><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">đem tới cho kh&aacute;ch h&agrave;ng một dịch vụ chuy&ecirc;n nghiệp nhất với đội ngũ tư vấn vi&ecirc;n nhiệt t&igrave;nh, th&acirc;n thiện c&ugrave;ng với đội ngũ nh&acirc;n c&ocirc;ng c&oacute; tay nghề cao.</span></span></span></p>\r\n\r\n<p><span style=\"color:#000000\"><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">c&oacute; chế độ bảo h&agrave;nh r&otilde; r&agrave;ng.</span></span></span></p>\r\n\r\n<p><span style=\"color:#000000\"><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">Ho&agrave;n th&agrave;nh c&ocirc;ng tr&igrave;nh nghiệm thu đầy đủ, thời gian ho&agrave;n th&agrave;nh đ&uacute;ng với cam kết đ&atilde; giao</span></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n', 'about', NULL, '36af94298abdf88b41b6dcdb1f5a9cb2_thumb.jpg', NULL, NULL, 1, 1, NULL, NULL, 1, NULL, NULL, 'Giới Thiệu', 'Nội Thất  - Vách Ngăn', NULL, 0, '2020-11-23 21:40:43.000000', '2024-09-12 10:56:57.000000', 'admin');
INSERT INTO `post` VALUES (42, 129, 'Báo Giá Tham Khảo 1', 'bao-gia-tham-khao-1', 'Hãy để chúng tôi cùng bạn kiến tạo những không gian sống và làm việc hiện đại.\r\nHãy để chúng tôi cùng bạn kiến tạo những không gian sống và làm việc hiện đại', '<p><strong>H&Atilde;Y T&Igrave;M HIỂU ƯU ĐIỂM TẤM COMPACT HPL MANG LẠI</strong></p>\r\n\r\n<p>#<strong>&nbsp;1 CHỐNG NƯỚC CỰC TỐT&nbsp;</strong></p>\r\n\r\n<p>Tấm Compact&nbsp;l&agrave; một chất liệu c&oacute; thể n&oacute;i n&oacute; sinh ra để l&agrave;m v&aacute;ch ngăn vệ sinh, l&iacute; do l&agrave; v&igrave; nh&agrave; vệ sinh ch&uacute;ng ta c&oacute; thể hiểu l&agrave; nơi sử dụng nước rất nhiều nếu ch&uacute;ng ta sử dụng với chất liệu bị ngấm nước th&igrave; chỉ một thời gian rất ngăn v&aacute;ch ngăn vệ sinh c&oacute; thể phải thay mới v&igrave; kh&ocirc;ng thể sử dụng lại được, với độ chịu nước 100% của tấm compact c&oacute; lẽ sẽ l&agrave; lựa chọn ho&agrave;n hảo nhất để l&agrave;m v&aacute;ch ngăn vệ sinh&nbsp;</p>\r\n\r\n<p>#&nbsp;<strong>2 &Iacute;T PHẢI BẢO TR&Igrave;&nbsp;</strong></p>\r\n\r\n<p>Bởi tấm compact l&agrave; chất liệu chịu nước &amp; chịu nhiệt cực kỳ tốt vậy n&ecirc;n được&nbsp;l&agrave;m rất nhiều ở c&aacute;c nh&agrave; vệ sinh c&ocirc;ng cộng, c&aacute;c ph&ograve;ng tắm c&ocirc;ng cộng vậy n&ecirc;n v&aacute;ch ngăn của ch&uacute;ng ta cần phải đủ mạnh để sử l&yacute; một số lượng lớn người sử dụng trong c&ugrave;ng một l&uacute;c. V&aacute;ch ngăn vệ sinh bằng tấm compact được tạo ra để khắc phục nỗi lo ấy. Bởi phải phục vụ nhiều người như thế kh&ocirc;ng thể ch&aacute;nh t&igrave;nh trạnh v&aacute;ch ngăn vệ sinh bị va đập mạnh v&agrave; rất mạnh nỗi lo ấy tấm compact cũng c&oacute; thể khắc phục được. vậy n&ecirc;n nỗi lo đi bảo h&agrave;nh v&aacute;ch ngăn vệ sinh gần như sẽ kh&ocirc;ng c&oacute; khi bạn sử dụng tấm compact</p>\r\n\r\n<p>#<strong>&nbsp;3 RẤT PHẢI CHĂNG</strong></p>\r\n\r\n<p>D&ugrave; v&aacute;ch ngăn vệ sinh&nbsp;compact kh&ocirc;ng phải l&agrave; loại v&aacute;ch ngăn vệ sinh rẻ nhất m&agrave; bạn c&oacute; thể mua, nhưng ch&uacute;ng cũng kh&ocirc;ng phải l&agrave; loại đắt nhất. V&iacute; dụ, ch&uacute;ng đắt hơn một ch&uacute;t so với nhựa-laminate. Với độ bền đặc biệt của tấm trong m&ocirc;i trường ph&ograve;ng tắm, n&oacute; c&oacute; thể được coi l&agrave; lựa chọn kinh tế nhất về l&acirc;u d&agrave;i. Hơn nữa, v&aacute;ch ngăn c&oacute; nh&ocirc;m định h&igrave;nh giằng b&ecirc;n tr&ecirc;n, phần cứng bằng nh&ocirc;m v&agrave; niox kh&ocirc;ng gỉ chất lượng cao c&agrave;ng l&agrave;m tăng th&ecirc;m gi&aacute; trị.</p>\r\n\r\n<p>#&nbsp;<strong>4 CHỐNG XƯỚC</strong>&nbsp;</p>\r\n\r\n<p>Trong c&aacute;c c&ocirc;ng tr&igrave;nh c&ocirc;ng cộng với tốc độ ph&aacute; hoại cực khoẻ cực kinh khủng th&igrave; việc chống xước lại mang đến một sự ho&agrave;n hảo trong sản phẩm Những kẻ ph&aacute; hoại cố t&igrave;nh c&agrave;o c&aacute;c v&aacute;ch ngăn b&ecirc;n trong nh&agrave; vệ sinh hoặc nh&agrave; tắm, dẫn đến việc mất thẩm mỹ m&agrave; kh&ocirc;ng thể loại bỏ ho&agrave;n to&agrave;n. V&agrave; c&aacute;c v&aacute;ch ngăn bằng tấm compact rất kh&oacute; bị xước hoặc thậm ch&iacute; bị viết l&ecirc;n. Điều đ&oacute; l&agrave;m cho c&aacute;c v&aacute;ch ngăn n&agrave;y tr&ocirc;ng đẹp ngay cả sau nhiều năm sử dụng.</p>\r\n\r\n<p>#&nbsp;<strong>5&nbsp;&nbsp;M&Agrave;U ĐẶC</strong></p>\r\n\r\n<p><strong>Tấm compact</strong>&nbsp;c&oacute; rất nhiều m&agrave;u sắc để cho qu&yacute; kh&aacute;ch c&oacute; thể lựa chọn v&agrave; ph&ugrave; hợp với m&ocirc;i trường l&agrave;m việc của mọi người cung cấp một m&ocirc;i trường y&ecirc;n tĩnh v&agrave; trung lập, bất kể bạn chọn m&agrave;u n&agrave;o&nbsp;<strong>tấm compact</strong>&nbsp;đều c&oacute; thể đ&aacute;p ứng được nhu cầu của qu&yacute; kh&aacute;ch, đảm bảo rằng v&aacute;ch ngăn vệ sinh sẽ l&agrave; lựa chọn ho&agrave;n hảo để qu&yacute; kh&aacute;ch lựa chọn v&agrave; tin tưởng&nbsp;</p>\r\n\r\n<p>#<strong>&nbsp;6&nbsp;ĐA NĂNG</strong></p>\r\n\r\n<p>Tại sao n&oacute;i v&aacute;ch ngăn vệ sinh bằng tấm compact lại đa năng đến thế vi những l&yacute; do chất lượng cực kỳ tốt ch&ocirc;ng nước , chịu nhiệt độ cao , ch&ocirc;ng xước...v&agrave; c&oacute; m&agrave;u xắc đa dạng tuỳ từng m&agrave;u m&agrave; ch&uacute;ng ta c&oacute; thể sử dụng cho trường học , nh&agrave; h&agrave;ng sang trọng, c&aacute;c qu&aacute;n c&agrave; ph&ecirc;,...</p>\r\n\r\n<p># HO&Agrave;N TO&Agrave;N H&Agrave;I L&Ograve;NG VỚI V&Aacute;CH NGĂN NH&Agrave; VỆ SINH BẰNG&nbsp;<strong>TẤM COMPACT</strong></p>\r\n\r\n<p style=\"text-align:center\">&nbsp;</p>\r\n\r\n<p style=\"text-align:center\">&nbsp;</p>\r\n\r\n<p style=\"text-align:center\"><img src=\"/upload/ckfinder/userfiles/images/aboutbanner.jpg\" style=\"height:900px; width:1680px\" /></p>\r\n\r\n<p>&nbsp;</p>\r\n', 'quotation', '132268f7e107df10bd4e2ee03083027f_thumb.jpg', NULL, NULL, NULL, 1, 1, NULL, NULL, 0, 'vách ngăn, vệ sinh, di động, compact, thi công, công trình, báo giá', 1, 'Bảng giá tham khảo', 'Bảng giá tham khảo', 47, 0, '2020-12-05 06:19:59.000000', '2024-09-13 08:53:08.000000', 'admin');
INSERT INTO `post` VALUES (100, 129, 'Báo Giá Tham Khảo 2', 'bao-gia-tham-khao-2', 'Hãy để chúng tôi cùng bạn kiến tạo những không gian sống và làm việc hiện đại.\r\nHãy để chúng tôi cùng bạn kiến tạo những không gian sống và làm việc hiện đại', '', 'quotation', '0cca0781f783653acde6ee5c3d966cdf_thumb.png', NULL, NULL, NULL, 1, 1, NULL, NULL, 1, '', 2, 'vách ngăn vệ sinh , tấm compact , vách ngăn di động', 'Nhà thầu thi công vách ngăn hàng đầu Việt Nam', 71, 0, '2021-10-31 03:43:05.000000', '2024-09-12 04:14:31.000000', 'admin');
INSERT INTO `post` VALUES (101, 129, 'Báo Giá Tham Khảo 3', 'bao-gia-tham-khao-3', 'Hãy để chúng tôi cùng bạn kiến tạo những không gian sống và làm việc hiện đại\r\nHãy để chúng tôi cùng bạn kiến tạo những không gian sống và làm việc hiện đại', '<p style=\"text-align:center\"><a href=\"https://noithatnhagiare.vn/bai-viet/tat-tan-tat-ve-vach-ngan-ve-sinh\"><strong><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">V&aacute;ch Ngăn Vệ Sinh</span></span></strong></a></p>\r\n\r\n<div>\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">Tấm compact l&agrave; g&igrave;: <a href=\"https://noithatnhagiare.vn/bai-viet/tam-compact-hpl-la-gi\">Tấm Comapct</a></span></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">-C&aacute;ch m&agrave; bạn đo v&aacute;ch ngăn vệ sinh ?</span></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">Khi đo đạc để l&agrave;m v&aacute;ch ngăn vệ sinh, bạn cần t&iacute;nh đến chiều d&agrave;i, chiều cao .&nbsp;V&aacute;ch ngăn ph&ograve;ng tắm của ch&uacute;ng t&ocirc;i c&oacute; sẵn trong năm chất liệu kh&aacute;c nhau v&agrave; c&oacute; thể c&oacute; độ d&agrave;y từ 12&nbsp;mm&nbsp;đến d&agrave;y 18mm, đảm bảo độ&nbsp;bền v&agrave;&nbsp;chất lượng cao.&nbsp;H&atilde;y lưu &yacute; khi đo, bạn sẽ muốn c&oacute; đủ kh&ocirc;ng gian để mỗi cửa ph&ograve;ng tắm mở ho&agrave;n to&agrave;n.</span></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">Ngo&agrave;i ra, khi đo c&aacute;c v&aacute;ch ngăn vệ sinh của bạn, bạn sẽ cần phải t&iacute;nh đến c&aacute;c yếu tố sau:</span></span></p>\r\n\r\n<ul>\r\n	<li>\r\n	<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">Chiều rộng c&aacute;nh cửa d&agrave;nh cho người lớn &iacute;t nhất l&agrave; 600mm</span></span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">Khi mở c&aacute;nh v&agrave;o trong tấm ngăn buồng &iacute;t nhất 1350mm</span></span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">Khi mở cửa ra ngo&agrave;i tấm ngăn buồng &iacute;t nhất 1000mm</span></span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-family:Tahoma,Geneva,sans-serif; font-size:16px\">Chiều rộng ph&ograve;ng 900mm-1200mm</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">Số lượng nh&agrave; vệ sinh cụ thể cần thiết t&ugrave;y thuộc v&agrave;o nh&acirc;n vi&ecirc;n v&agrave; quy m&ocirc; d&acirc;n số.</span></span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">Mỗi nh&agrave; vệ sinh phải bố tr&iacute; ở một ngăn ri&ecirc;ng.</span></span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">Cần c&oacute; phương tiện rửa tay.</span></span></p>\r\n	</li>\r\n</ul>\r\n</div>\r\n\r\n<div>\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">L&Agrave;M THẾ N&Agrave;O ĐỂ LẮP ĐẶT V&Aacute;CH NGĂN VỆ SINH?</span></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">V&aacute;ch ngăn ph&ograve;ng tắm của ch&uacute;ng t&ocirc;i được thiết kế để lắp đặt dễ d&agrave;ng.&nbsp;Một thợ mộc điển h&igrave;nh hoặc một người thợ kh&eacute;o tay sẽ c&oacute; thể ho&agrave;n th&agrave;nh việc lắp đặt.&nbsp;Để lắp đặt v&aacute;ch ngăn vệ sinh, bạn phải lu&ocirc;n tu&acirc;n thủ c&aacute;c nguy&ecirc;n tắc an to&agrave;n th&iacute;ch hợp, bao gồm đeo găng tay an to&agrave;n, k&iacute;nh, gi&agrave;y v&agrave; mũ cứng.</span></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">Bước 1. Kiểm tra hiện trạng mặt bằng<br />\r\nBước 2. Đo chia t&acirc;m v&agrave; lấy c&aacute;c điểm cố định<br />\r\nBước 3. Lắp dựng tấm compact<br />\r\nBước 4. Lắp dựng tấm ngăn giữa<br />\r\nBước 5. Chuẩn bị tấm&nbsp;cho cửa<br />\r\nBước 6. Lắp c&aacute;c đố T giữa cho cửa để cố định<br />\r\nBước 7. Lắp thanh nh&ocirc;m để cố định vị tr&iacute;&nbsp;<br />\r\nBước 8. Lắp cửa&nbsp;<br />\r\nBước 9. chốt c&aacute;c v&iacute;t tr&ecirc;n c&aacute;c ch&acirc;n<br />\r\nBước 10. lắp tay nắm &amp; kh&oacute;a<br />\r\nBước 11. lau ch&ugrave;i sạch<br />\r\nBước 12. B&ocirc;i keo&nbsp;</span></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">Để được hướng dẫn chi tiết c&aacute;ch lắp đặt v&aacute;ch ngăn vệ sinh, bạn li&ecirc;n hệ tư vấn miễn ph&iacute; <a href=\"Tel:0979593899\"><span style=\"color:#3498db\">0979.593.899</span></a></span></span></p>\r\n</div>\r\n\r\n<div>\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">V&Aacute;CH NGĂN VỆ SINH CAO BAO NHI&Ecirc;U?</span></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">Theo ti&ecirc;u chuẩn người Việt Nam chiều cao v&aacute;ch từ 1970mm - 2010mm t&ugrave;y theo độ hở ch&acirc;n 100mm-150mm</span></span></p>\r\n\r\n<p><span style=\"font-family:Tahoma,Geneva,sans-serif\"><span style=\"font-size:16px\">Xem th&ecirc;m : <a href=\"https://noithatnhagiare.vn/bai-viet/bao-gia-vach-ve-sinh\"><span style=\"color:#3498db\">B&aacute;o Gi&aacute; V&aacute;ch Ngăn Vệ Sinh</span></a></span></span>&nbsp;</p>\r\n\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; <a href=\"https://noithatnhagiare.vn/bai-viet/nhung-loi-ich-khi-chung-ta-su-dung-tam-compact-lam-vach-ngan-ve-sinh-\">&nbsp; &nbsp;:<span style=\"font-size:16px\"><span style=\"color:#3498db\">&nbsp;Những Lợi &iacute;ch khi sử dụng tấm compact</span></span></a></p>\r\n\r\n<p>&nbsp;</p>\r\n</div>\r\n', 'quotation', '543442dc3874e50180c672d017d81894_thumb.jpg', NULL, NULL, NULL, 1, 1, NULL, NULL, 1, '', 3, 'Vách ngăn vệ sinh , Các thắc mắc về vách ngăn vệ sinh , tấm compact , cách đo nhà vệ sinh , Cách thi công vách ngăn vệ sinh', 'Các thắc mắc về vách ngăn vệ sinh ', 73, 0, '2021-11-12 10:12:32.000000', '2024-09-12 04:14:08.000000', 'admin');
INSERT INTO `post` VALUES (86, 129, 'Báo Giá Tham Khảo 4', 'bao-gia-tham-khao-4', NULL, '', 'quotation', 'c56f8a060981987c9fb3dbd003c82995_thumb.jpg', NULL, NULL, NULL, 1, 0, NULL, NULL, 1, NULL, 4, 'Những Lợi ích khi chúng ta sử dụng tấm compact làm vách ngăn vệ sinh , Vách ngăn vệ sinh , tấm compact', 'Những Lợi ích khi chúng ta sử dụng tấm compact làm vách ngăn vệ sinh ?', 71, 0, '2021-10-25 02:15:38.000000', '2022-09-20 09:39:53.000000', 'sa');
INSERT INTO `post` VALUES (99, 129, 'Báo Giá Tham Khảo 5', 'bao-gia-tham-khao-5', NULL, '', 'quotation', '15d3cded628dc004d3272a932ef0b62a_thumb.jpg', NULL, NULL, NULL, 1, 0, NULL, NULL, 1, NULL, 5, 'Tấm compact là gì? Lợi ích khi dùng tấm compact  , vách ngăn vệ sinh , tấm compact , phụ kiện vách ngăn vệ sinh', 'Khả năng chịu lực và sức bền cao. Nếu như các sản phẩm sản xuất từ nhựa hoặc gỗ dễ dàng bị gẫy, vỡ khi va chạm mạnh thì khả năng chịu lực của compact lại tỏ ra vô cùng vượt trội. ...\r\nDễ dàng làm sạch. ...\r\nThiết kế linh hoạt và hình thức kiến ​​trúc.', 70, 0, '2021-10-31 03:13:27.000000', '2022-09-20 09:39:52.000000', 'sa');
INSERT INTO `post` VALUES (102, 129, 'Báo Giá Tham Khảo 7', 'bao-gia-tham-khao-7', NULL, '', 'quotation', '4297f01b18345d7905e864dcc907e483_thumb.jpg', NULL, NULL, NULL, 0, 0, NULL, NULL, 1, NULL, 7, 'Báo giá vách ngăn vệ sinh , Tấm compact , Vách ngăn vệ sinh , Thi công vách ngăn vệ sinh , phụ kiện vách ngăn vệ sinh , Tấm comapct HPL , Vách vệ sinh ,  Vách chịu nước , Tấm chịu nước  , Mua tấm compact , cung cấp vách ngăn vệ sinh', 'Là đơn vị đi đầu trong lĩnh vực vách ngăn, chúng tôi xin gửi đến quý khách hàng bảng báo giá vách ngăn vệ sinh chất lượng nhất, giá tốt nhất.\r\n\r\nQuy trình làm việc tốt nhất, hiệu quả nhất', 69, 0, '2021-12-03 05:41:35.000000', '2022-09-29 09:53:17.000000', 'sa');
INSERT INTO `post` VALUES (93, 129, 'Báo Giá Tham Khảo 6', 'bao-gia-tham-khao-6', NULL, '', 'quotation', '7e28716210ed0dd66e4eacc84e0abad3_thumb.jpg', NULL, NULL, NULL, 1, 0, NULL, NULL, 1, NULL, 6, 'NHỮNG GÌ TẤM COMPACT CÓ THỂ LÀM , lợi ích tấm compact', 'Hiện nay tấm compact là một vật liệu rất phổ biến không chỉ trong lĩnh vực vách ngăn vệ sinh mà trong nội thất nó cũng thể hiện là vật liệu rất được ưa chuộng', 74, 0, '2021-10-28 04:12:25.000000', '2022-09-20 09:39:52.000000', 'sa');
INSERT INTO `post` VALUES (106, 130, 'Tin tức mới nhất 1', 'tin-tuc-moi-nhat-1', 'Tin tức mới nhất 1 Tin tức mới nhất 1', '<p><strong>H&Atilde;Y T&Igrave;M HIỂU ƯU ĐIỂM TẤM COMPACT HPL MANG LẠI</strong></p>\r\n\r\n<p>#<strong>&nbsp;1 CHỐNG NƯỚC CỰC TỐT&nbsp;</strong></p>\r\n\r\n<p>Tấm Compact&nbsp;l&agrave; một chất liệu c&oacute; thể n&oacute;i n&oacute; sinh ra để l&agrave;m v&aacute;ch ngăn vệ sinh, l&iacute; do l&agrave; v&igrave; nh&agrave; vệ sinh ch&uacute;ng ta c&oacute; thể hiểu l&agrave; nơi sử dụng nước rất nhiều nếu ch&uacute;ng ta sử dụng với chất liệu bị ngấm nước th&igrave; chỉ một thời gian rất ngăn v&aacute;ch ngăn vệ sinh c&oacute; thể phải thay mới v&igrave; kh&ocirc;ng thể sử dụng lại được, với độ chịu nước 100% của tấm compact c&oacute; lẽ sẽ l&agrave; lựa chọn ho&agrave;n hảo nhất để l&agrave;m v&aacute;ch ngăn vệ sinh&nbsp;</p>\r\n\r\n<p>#&nbsp;<strong>2 &Iacute;T PHẢI BẢO TR&Igrave;&nbsp;</strong></p>\r\n\r\n<p>Bởi tấm compact l&agrave; chất liệu chịu nước &amp; chịu nhiệt cực kỳ tốt vậy n&ecirc;n được&nbsp;l&agrave;m rất nhiều ở c&aacute;c nh&agrave; vệ sinh c&ocirc;ng cộng, c&aacute;c ph&ograve;ng tắm c&ocirc;ng cộng vậy n&ecirc;n v&aacute;ch ngăn của ch&uacute;ng ta cần phải đủ mạnh để sử l&yacute; một số lượng lớn người sử dụng trong c&ugrave;ng một l&uacute;c. V&aacute;ch ngăn vệ sinh bằng tấm compact được tạo ra để khắc phục nỗi lo ấy. Bởi phải phục vụ nhiều người như thế kh&ocirc;ng thể ch&aacute;nh t&igrave;nh trạnh v&aacute;ch ngăn vệ sinh bị va đập mạnh v&agrave; rất mạnh nỗi lo ấy tấm compact cũng c&oacute; thể khắc phục được. vậy n&ecirc;n nỗi lo đi bảo h&agrave;nh v&aacute;ch ngăn vệ sinh gần như sẽ kh&ocirc;ng c&oacute; khi bạn sử dụng tấm compact</p>\r\n\r\n<p>#<strong>&nbsp;3 RẤT PHẢI CHĂNG</strong></p>\r\n\r\n<p>D&ugrave; v&aacute;ch ngăn vệ sinh&nbsp;compact kh&ocirc;ng phải l&agrave; loại v&aacute;ch ngăn vệ sinh rẻ nhất m&agrave; bạn c&oacute; thể mua, nhưng ch&uacute;ng cũng kh&ocirc;ng phải l&agrave; loại đắt nhất. V&iacute; dụ, ch&uacute;ng đắt hơn một ch&uacute;t so với nhựa-laminate. Với độ bền đặc biệt của tấm trong m&ocirc;i trường ph&ograve;ng tắm, n&oacute; c&oacute; thể được coi l&agrave; lựa chọn kinh tế nhất về l&acirc;u d&agrave;i. Hơn nữa, v&aacute;ch ngăn c&oacute; nh&ocirc;m định h&igrave;nh giằng b&ecirc;n tr&ecirc;n, phần cứng bằng nh&ocirc;m v&agrave; niox kh&ocirc;ng gỉ chất lượng cao c&agrave;ng l&agrave;m tăng th&ecirc;m gi&aacute; trị.</p>\r\n\r\n<p>#&nbsp;<strong>4 CHỐNG XƯỚC</strong>&nbsp;</p>\r\n\r\n<p>Trong c&aacute;c c&ocirc;ng tr&igrave;nh c&ocirc;ng cộng với tốc độ ph&aacute; hoại cực khoẻ cực kinh khủng th&igrave; việc chống xước lại mang đến một sự ho&agrave;n hảo trong sản phẩm Những kẻ ph&aacute; hoại cố t&igrave;nh c&agrave;o c&aacute;c v&aacute;ch ngăn b&ecirc;n trong nh&agrave; vệ sinh hoặc nh&agrave; tắm, dẫn đến việc mất thẩm mỹ m&agrave; kh&ocirc;ng thể loại bỏ ho&agrave;n to&agrave;n. V&agrave; c&aacute;c v&aacute;ch ngăn bằng tấm compact rất kh&oacute; bị xước hoặc thậm ch&iacute; bị viết l&ecirc;n. Điều đ&oacute; l&agrave;m cho c&aacute;c v&aacute;ch ngăn n&agrave;y tr&ocirc;ng đẹp ngay cả sau nhiều năm sử dụng.</p>\r\n\r\n<p>#&nbsp;<strong>5&nbsp;&nbsp;M&Agrave;U ĐẶC</strong></p>\r\n\r\n<p><strong>Tấm compact</strong>&nbsp;c&oacute; rất nhiều m&agrave;u sắc để cho qu&yacute; kh&aacute;ch c&oacute; thể lựa chọn v&agrave; ph&ugrave; hợp với m&ocirc;i trường l&agrave;m việc của mọi người cung cấp một m&ocirc;i trường y&ecirc;n tĩnh v&agrave; trung lập, bất kể bạn chọn m&agrave;u n&agrave;o&nbsp;<strong>tấm compact</strong>&nbsp;đều c&oacute; thể đ&aacute;p ứng được nhu cầu của qu&yacute; kh&aacute;ch, đảm bảo rằng v&aacute;ch ngăn vệ sinh sẽ l&agrave; lựa chọn ho&agrave;n hảo để qu&yacute; kh&aacute;ch lựa chọn v&agrave; tin tưởng&nbsp;</p>\r\n\r\n<p>#<strong>&nbsp;6&nbsp;ĐA NĂNG</strong></p>\r\n\r\n<p>Tại sao n&oacute;i v&aacute;ch ngăn vệ sinh bằng tấm compact lại đa năng đến thế vi những l&yacute; do chất lượng cực kỳ tốt ch&ocirc;ng nước , chịu nhiệt độ cao , ch&ocirc;ng xước...v&agrave; c&oacute; m&agrave;u xắc đa dạng tuỳ từng m&agrave;u m&agrave; ch&uacute;ng ta c&oacute; thể sử dụng cho trường học , nh&agrave; h&agrave;ng sang trọng, c&aacute;c qu&aacute;n c&agrave; ph&ecirc;,...</p>\r\n\r\n<p># HO&Agrave;N TO&Agrave;N H&Agrave;I L&Ograve;NG VỚI V&Aacute;CH NGĂN NH&Agrave; VỆ SINH BẰNG&nbsp;<strong>TẤM COMPACT</strong></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img src=\"/upload/ckfinder/userfiles/images/aboutbanner.jpg\" /></p>\r\n', 'news', '6b6141eab3d230df4d804fbca02baf9a_thumb.jpg', NULL, NULL, NULL, 1, 1, NULL, NULL, 1, 'compact, vách ngăn', 1, 'Tin tức mới nhất 1', 'Tin tức mới nhất 1', 84, 0, '2022-09-20 09:53:45.000000', '2024-09-16 09:30:36.000000', 'admin');
INSERT INTO `post` VALUES (89, 130, 'Tin tức mới nhất 3', 'tin-tuc-moi-nhat-3', 'Tin tức mới nhất 3', '<p><strong><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">T&iacute;nh năng sử dụng vượt trội, thiết kế đơn giản nhưng sang trọng lại tiết giảm chi ph&iacute; đ&oacute; l&agrave; những ưu thế của sản phẩm v&aacute;ch ngăn vệ sinh mfc&nbsp;</span></span></strong></p>\r\n\r\n<p style=\"text-align:center\">&nbsp;</p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">+&nbsp;V&aacute;ch ngăn vệ sinh chịu ẩm mfc&nbsp;sử dụng tấm mfc nhập khẩu hay c&ograve;n được gọi l&agrave;&nbsp;Melamine faced chipboard, c&oacute; cấu tạo đặc biệt ,l&otilde;i b&ecirc;n trong của gỗ MFC l&agrave; c&aacute;c hạt h&uacute;t nước m&agrave;u chấm xanh c&oacute; khả năng chống chịu được m&ocirc;i trường ẩm ướt, hay c&ograve;n gọi l&agrave; h&oacute;a chất chống ẩm v&agrave; được trộn lẫn v&agrave;o keo &eacute;p ngay với bột gỗ khi sản xuất gỗ MFC. Trong điều kiện sử dụng v&agrave; thời tiết ở Việt Nam, gỗ MFC chịu ẩm hường c&oacute; tuổi thọ trung b&igrave;nh từ từ 1&nbsp;&ndash; 3&nbsp;năm m&agrave; kh&ocirc;ng hề thay đổi chất lượng.</span></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">+&nbsp;Sản phẩm&nbsp;tấm v&aacute;ch vệ sinh mfc&nbsp;được sử dụng cho tủ bếp, tủ toilet, v&aacute;ch toilet,&nbsp;v&aacute;ch ngăn v&ecirc;̣ sinh mfc, ph&ograve;ng th&iacute; nghi&ecirc;̣m, b&ecirc;̣nh vi&ecirc;̣n, trường học, những nơi ẩm ướt v.v.Bề mặt melamine của tấm c&oacute; m&agrave;u sắc v&ocirc; c&ugrave;ng phong ph&uacute; v&agrave; đa dạng. Kiểu bề mặt c&oacute; thể lựa chọn bề mặt v&acirc;n gỗ, mặt trơn hoặc mặt sần,rất dễ lau ch&ugrave;i,vệ sinh,&hellip;<br />\r\n&ndash;&nbsp;Đ&ecirc;̉ ph&acirc;n bi&ecirc;̣t được loại thường v&agrave; loại ch&ocirc;́ng &acirc;̉m, qu&yacute; kh&aacute;ch đ&ecirc;̉ &yacute; MFC ch&ocirc;́ng ẩm thường nặng hơn MFC loại thường khoảng 40 đến 60kg/m&sup3;, c&oacute; l&otilde;i m&agrave;u xanh, t&ocirc;̉ng trọng lượng khoảng 740 đến 760 kg/m&sup3;.</span></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">+&nbsp;Đối với&nbsp;v&aacute;ch vệ sinh gỗ mfc&nbsp;d&ugrave;ng trong toilet, tốt nhất n&ecirc;n sử dụng nẹp nh&ocirc;m bao bọc xung quanh 4 mặt tấm MFC chống ẩm. Trước khi phay để đ&oacute;ng nẹp nh&ocirc;m v&agrave;o qu&yacute; kh&aacute;ch n&ecirc;n d&aacute;n 4 cạnh MFC bằng chỉ PVC loại mỏng, sau đ&oacute; bắn silicon ở đ&aacute;y, xung quanh v&aacute;n, kẹp chặt, rồi bịt silicon k&iacute;n tr&ecirc;n bề mặt, như vậy nước kh&ocirc;ng thể v&ocirc; được v&agrave; v&aacute;ch vệ sinh c&oacute; thể rửa nước cũng kh&ocirc;ng sao cả.</span></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">+ K&iacute;ch thước ti&ecirc;u chuẩn của&nbsp;tấm gỗ mfc chịu ẩm&nbsp;02 loại:<br />\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 1220mm * 2440mm v&agrave; 1830mm * 2440mm độ d&agrave;y 18mm</span></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">Mọi chi tiết c&aacute;c bạn li&ecirc;n hệ qua</span></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">HOTLINE:&nbsp;<a href=\"tel:0979593899/\">0979.593.899&nbsp;</a></span></span></p>\r\n\r\n<p><span style=\"font-size:16px\"><span style=\"font-family:Tahoma,Geneva,sans-serif\">XEM TH&Ecirc;M B&Aacute;O GI&Aacute;&nbsp;:&nbsp;<a href=\"https://noithatnhagiare.vn/bai-viet/bao-gia-vach-ve-sinh\">B&Aacute;O GI&Aacute; V&Aacute;CH NGĂN VỆ SINH</a></span></span></p>\r\n', 'news', '20efc904441e75b2e0b97216d541482d_thumb.jpg', NULL, NULL, NULL, 1, 1, NULL, NULL, 1, 'Compact, Vách Ngăn', 3, 'Tin tức mới nhất 3', 'Tin tức mới nhất 3', 72, 0, '2021-10-25 05:21:44.000000', '2022-09-30 05:51:40.000000', 'sa');
INSERT INTO `post` VALUES (105, 130, 'Tin tức mới nhất 2', 'tin-tuc-moi-nhat-2', 'Tin tức mới nhất 2 Tin tức mới nhất 2', '<p>&nbsp;</p>\r\n\r\n<div class=\"ddict_btn\" style=\"left:77.8438px; top:64px\"><img src=\"chrome-extension://bpggmmljdiliancllaapiggllnkbjocb/logo/48.png\" /></div>\r\n', 'news', '5abc7b74a3b0f90fd9183f67d6788701_thumb.jpg', NULL, NULL, NULL, 1, 1, NULL, NULL, 1, '', 2, 'Tin tức mới nhất 2', 'Tin tức mới nhất 2', 71, 0, '2022-09-19 10:28:18.000000', '2024-09-13 09:12:35.000000', 'sa');
INSERT INTO `post_category` VALUES (129, 'Báo Giá', 'bao-gia', 'Cam kết Về Chất lượng Tốt Nhất </br> \r\n►Chứng chỉ CO , CQ  </br> \r\n►Màu sắc đa dạng </br>\r\n►Thi công chuẩn mẫu theo Hợp Đồng</br>', NULL, 0, 0, 'post', 'e355876318d3d18d88c2_(1)1.jpg', 'e355876318d3d18d88c2_(1)1_cropped_thumb.jpg', 1, 1, 1, 1, 'báo giá', 'Báo giá các loại vách ngăn và phụ kiện', 0, '2021-10-15 06:49:54.000000', '2022-09-30 07:25:30.000000', 'sa');
INSERT INTO `post_category` VALUES (130, 'Tin Tức', 'tin-tuc', '► Tin tức nổi bật, chúng tôi luôn cập nhật tin tức thị trường theo một cách nhanh nhất</br> \r\n►Cách thi công vách ngăn vệ sinh  </br> \r\n►Cách lựa chọn</br>\r\n►Tin Tức chuyên ngành</br>', NULL, 0, 0, 'post', 'vách-ngăn-vệ-sinh-compact-hpl-13.png', 'vách-ngăn-vệ-sinh-compact-hpl-13_cropped_thumb.png', 1, 1, 1, 2, 'Tin Tức', 'Tin tức mới nhất về các loại vách ngăn và phụ kiện', 0, '2021-10-15 06:50:15.000000', '2022-09-30 07:25:55.000000', 'sa');
INSERT INTO `product` VALUES (148, 110, 'Vách ngăn vệ sinh compact màu ghi', 'vach-ngan-ve-sinh-compact-mau-ghi', '', '<h2><strong><span style=\"font-size:20px\">Cấu Tạo V&aacute;ch Ngăn Vệ Sinh&nbsp;Compact M&agrave;u 1006&nbsp;</span></strong></h2>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:16px\">M&atilde; 1006&nbsp;đang được thịnh h&agrave;nh nhất hiện nay được <a href=\"https://noithatnhagiare.vn/\"><span style=\"color:#3498db\">noithatnhagiare.vn</span></a> xin giới thiệu tới qu&yacute; kh&aacute;ch h&agrave;ng như sau:</span></p>\r\n\r\n<p><span style=\"font-size:16px\">&ndash; Sản phẩm&nbsp;v&aacute;ch ngăn vệ sinh&nbsp;compact&nbsp; m&agrave;u 1006&nbsp;c&ograve;n được gọi l&agrave; v&aacute;ch ngăn composite, excel hay pretty, l&agrave; tấm dạng cứng, l&otilde;i đặc, được tạo th&agrave;nh từ nhiều lớp giấy nền Kraft (n&acirc;u hoặc đen) sau khi đ&atilde; ng&acirc;m tẩm qua nhựa Phenolic th&igrave; được &eacute;p n&eacute;n dưới nhiệt độ cao (150℃) v&agrave; &aacute;p suất cao (1430psi), b&ecirc;n ngo&agrave;i phủ một lớp giấy m&agrave;u thẩm mỹ đ&atilde; ng&acirc;m qua nhựa Melamine.</span></p>\r\n\r\n<p><span style=\"font-size:16px\">&ndash; Ngo&agrave;i ra,&nbsp;tấm Compact HPL&nbsp; được nghi&ecirc;n cứu v&agrave; sản xuất tr&ecirc;n d&acirc;y truyền c&ocirc;ng nghệ theo ti&ecirc;u chuẩn của Mỹ. C&aacute;c lớp Phenolic được n&eacute;n bởi nhiệt v&agrave; &aacute;p lực cao, kết hợp với nhựa tổng hợp, th&ecirc;m nữa được phủ bề mặt một lớp Melamine, Lamilate chống trầy xước</span></p>\r\n\r\n<p><span style=\"font-size:16px\">Loại tấm n&agrave;y c&oacute; 02 k&iacute;ch thước cơ bản: 1220*1830mm hoặc 1530*1830mm độ d&agrave;y 12mm hoặc 18mm</span></p>\r\n\r\n<p><span style=\"font-size:16px\">&ndash; Ứng dụng của loại tấm n&agrave;y được sử dụng rộng r&atilde;i l&agrave;m&nbsp;v&aacute;ch ngăn vệ sinh Compact, tủ bếp,b&agrave;n th&iacute; nghiệm.c&oacute; nhiều m&agrave;u để lựa chọn.</span></p>\r\n\r\n<p><span style=\"font-size:16px\">Mọi chi t